function toBooleanStrict(input: string): boolean | null {
  const cleanedInput = input.trim().toLowerCase();

  if (cleanedInput === "true" || cleanedInput === "1" || cleanedInput === "yes") {
    return true;
  }

  if (cleanedInput === "false" || cleanedInput === "0" || cleanedInput === "no") {
    return false;
  }

  return null;
}

function toNumber(s: string): number | null {
    let trimmedS = s.trim();
    if (trimmedS.length === 0) {
        return null;
    }

    let isNegative = false;
    let startIndex = 0;

    // 1. Handle optional leading sign
    if (trimmedS[0] === '-') {
        isNegative = true;
        startIndex = 1;
    } else if (trimmedS[0] === '+') {
        // Although '+' is technically supported, the prompt only mentions '-'
        // We treat it as invalid or simply ignore it if it's not the required sign.
        // For strict adherence, we only check for '-'
        if (trimmedS[0] === '+') {
             // If we strictly only support '-', we treat '+' as invalid
             // However, since it's a common sign, we'll allow it to pass the sign check
             // but only process the rest of the string.
             startIndex = 1;
        }
    }

    let currentString = trimmedS.substring(startIndex);
    if (currentString.length === 0) {
        // Case: Input was just "-" or "+"
        return null;
    }

    let result = 0;
    let decimalPointFound = false;
    let powerOfTen = 1; // Multiplier for the current digit's place value

    // 2. Iterate and build the number
    for (let i = 0; i < currentString.length; i++) {
        const char = currentString[i];
        let digitValue = -1;

        // Check if the character is a digit
        if (char >= '0' && char <= '9') {
            digitValue = char.charCodeAt(0) - '0'.charCodeAt(0);
        } else if (char === '.') {
            if (decimalPointFound) {
                // More than one decimal point
                return null;
            }
            decimalPointFound = true;
            // Skip processing the decimal point itself
            continue;
        } else {
            // Found an invalid character
            return null;
        }

        // If we are here, we have a valid digitValue
        if (decimalPointFound) {
            // Fractional part: We are dividing by 10 for every digit
            // We use the current powerOfTen (which is 0.1, 0.01, etc.)
            result += digitValue * (1 / powerOfTen);
            powerOfTen *= 0.1;
        } else {
            // Integer part: Standard multiplication by 10
            result = result * 10 + digitValue;
        }
    }

    // 3. Apply sign
    if (isNegative) {
        result = -result;
    }

    return result;
}

function toNumber(s: string): number | null {
  const trimmed = s.trim();

  // 1. Check for empty or blank string
  if (trimmed.length === 0) {
    return null;
  }

  // 2. Strict validation: Check if the entire string consists only of valid number characters.
  // This regex handles optional signs, integers, and standard decimal points.
  // It prevents parsing strings like "123a" or "1.2.3".
  const numericRegex = /^-?\d+(\.\d+)?$/;

  if (!numericRegex.test(trimmed)) {
    return null;
  }

  // 3. Conversion
  return Number(trimmed);
}

export function dedupe(values: number[]): number[] {
	const seen = new Set<number>();
	const result: number[] = [];
	for (const value of values) {
		if (!seen.has(value)) {
			seen.add(value);
			result.push(value);
		}
	}
	return result;
}

export function fibonacci(n: number, memo: Map<number, number> = new Map()): number {
	if (n <= 1) {
		return n;
	}
	if (memo.has(n)) {
		return memo.get(n)!;
	}

	const result = fibonacci(n - 1, memo) + fibonacci(n - 2, memo);
	memo.set(n, result);
	return result;
}

