function centerText(text: string, width: number): string {
  if (text.length >= width) {
    return text;
  }

  const padding = width - text.length;

  // Calculate left padding (floored division)
  const leftPad = Math.floor(padding / 2);

  // Calculate right padding (ensures extra space goes right if padding is odd)
  const rightPad = padding - leftPad;

  const leftSpaces = ' '.repeat(leftPad);
  const rightSpaces = ' '.repeat(rightPad);

  return leftSpaces + text + rightSpaces;
}

function jaroWinkler(s1: string, s2: string): number {
    if (s1 === s2) return 1.0;
    if (s1.length === 0 || s2.length === 0) return 0.0;

    const len1 = s1.length;
    const len2 = s2.length;

    // 1. Calculate matching characters (m)
    const matchRange = Math.floor(Math.max(len1, len2) / 2) - 1;

    const matches1 = new Array(len1).fill(false);
    const matches2 = new Array(len2).fill(false);

    let m = 0;

    // Find matches
    for (let i = 0; i < len1; i++) {
        for (let j = 0; j < len2; j++) {
            // Check if characters match, are within the range, and haven't been matched yet
            if (s1[i] === s2[j] && !matches1[i] && !matches2[j]) {
                // Check range constraint: |i - j| <= matchRange
                if (Math.abs(i - j) <= matchRange) {
                    matches1[i] = true;
                    matches2[j] = true;
                    m++;
                    break; // Move to the next character in s1
                }
            }
        }
    }

    if (m === 0) return 0.0;

    // 2. Calculate transpositions (t)
    let k1 = ""; // Characters from s1 that matched
    let k2 = ""; // Characters from s2 that matched

    // Build matched character sequences
    for (let i = 0; i < len1; i++) {
        if (matches1[i]) {
            k1 += s1[i];
        }
    }
    for (let j = 0; j < len2; j++) {
        if (matches2[j]) {
            k2 += s2[j];
        }
    }

    let t = 0;
    for (let i = 0; i < m; i++) {
        if (k1[i] !== k2[i]) {
            t++;
        }
    }
    // Transpositions count is half the number of differing characters
    t = t / 2;

    // 3. Calculate Jaro Similarity (J)
    const jaro = (
        (m / len1) + (m / len2) + ((m - t) / m)
    ) / 3.0;

    // 4. Calculate Jaro-Winkler Similarity (JW)

    // Determine common prefix length (L)
    let l = 0;
    const prefixLimit = Math.min(4, Math.min(len1, len2));
    for (let i = 0; i < prefixLimit; i++) {
        if (s1[i] === s2[i]) {
            l++;
        } else {
            break;
        }
    }

    // Scaling factor (P) is typically 0.1
    const p = 0.1;

    // JW = J + (L * P * (1 - J))
    const jaroWinkler = jaro + (l * p * (1.0 - jaro));

    return jaroWinkler;
}

