type Status = 'idle' | 'loading' | 'done';

export function statusLabel(status: Status): string {
	switch (status) {
		case 'idle':
			return 'Idle';
		case 'loading':
			return 'Loading...';
		case 'done':
			return 'Done';
		default:
			const _exhaustiveCheck: never = status;
			throw new Error(`Unhandled status: ${(_exhaustiveCheck as any)}`);
	}
}

